using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Common English stop words excluded from scoring.
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","of","in","to","for",
        "with","on","at","from","by","about","as","into","through","during",
        "before","after","above","below","between","out","off","over","under",
        "again","further","then","once","it","its","this","that","these",
        "those","i","me","my","we","our","you","your","he","him","his","she",
        "her","they","them","their","what","which","who","whom","where","when",
        "how","not","no","nor","so","if","each","every","all","both","few",
        "more","most","other","some","such","only","own","same","than","too",
        "very","just","because","also","while","however","although","since"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index]);

        return string.Join(" ", scored);
    }

    public int CountSentences(string documentText) => SplitSentences(documentText).Count;

    private static List<string> SplitSentences(string text)
    {
        return SentenceBoundary().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = Tokenize(sentence).Where(w => !StopWords.Contains(w)).ToList();
        if (words.Count == 0) return 0;

        return words.Sum(w => wordFrequencies.GetValueOrDefault(w)) / (double)words.Count;
    }

    private static IEnumerable<string> Tokenize(string text) =>
        WordToken().Matches(text).Select(m => m.Value);

    [GeneratedRegex(@"[^.!?]*[.!?]+(\s|$)|[^.!?]+$", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial WordToken();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _service.Summarize(request.DocumentText, request.MaxSentences);
        var originalCount = _service.CountSentences(request.DocumentText);
        var summaryCount = _service.CountSentences(summary);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

